import React from 'react';
import { useNavigate } from 'react-router-dom';

const modules = [
  { to: '/trucks',      icon: '🚛', title: 'Truck Management',   desc: 'Trip entries, admin view, freight rates',       stat: null,      statLabel: null,           color: '#1a3a5c' },
  { to: '/scrap',       icon: '♻️', title: 'Scrap Management',   desc: 'Collected vs sold, stock, monthly summary',     stat: null,      statLabel: null,           color: '#065f46' },
  { to: '/diesel',      icon: '⛽', title: 'Diesel Inventory',   desc: 'Stock in/out, linked to trips, low-stock alert', stat: null,      statLabel: null,           color: '#92400e' },
  { to: '/dashboard',   icon: '📊', title: 'Dashboard',          desc: 'Revenue, expenses, per-truck performance',      stat: null,      statLabel: null,           color: '#3730a3' },
  { to: '/drivers',     icon: '👤', title: 'Driver Advances',    desc: 'Cash given vs spent, balance per driver',       stat: null,      statLabel: null,           color: '#831843' },
  { to: '/maintenance', icon: '🔧', title: 'Maintenance Log',    desc: 'Service history, next due, parts & cost',       stat: null,      statLabel: null,           color: '#7c2d12' },
  { to: '/customers',   icon: '🤝', title: 'Customer Ledger',    desc: 'Outstanding freight, payments, balance',        stat: null,      statLabel: null,           color: '#164e63' },
];

const quickActions = [
  { label: '+ New Trip',     to: '/trucks',      color: '#1a3a5c' },
  { label: '+ Add Diesel',   to: '/diesel',      color: '#92400e' },
  { label: '+ Log Scrap',    to: '/scrap',       color: '#065f46' },
];

export default function HomePage() {
  const navigate = useNavigate();
  return (
    <div>
      {/* Quick Actions */}
      <div style={s.qaRow}>
        {quickActions.map(a => (
          <button key={a.to} onClick={() => navigate(a.to)} style={{ ...s.qaBtn, background: a.color }}>
            {a.label}
          </button>
        ))}
      </div>

      {/* Module Grid */}
      <div style={s.grid}>
        {modules.map(m => (
          <div key={m.to} style={s.card} onClick={() => navigate(m.to)}>
            <div style={{ ...s.cardAccent, background: m.color }} />
            <div style={s.cardBody}>
              <div style={s.cardIcon}>{m.icon}</div>
              <div>
                <div style={s.cardTitle}>{m.title}</div>
                <div style={s.cardDesc}>{m.desc}</div>
              </div>
            </div>
            {m.stat !== null && (
              <div style={{ ...s.cardStat, color: m.color }}>
                <span style={s.statNum}>{m.stat}</span>
                <span style={s.statLabel}>{m.statLabel}</span>
              </div>
            )}
            <div style={{ ...s.cardArrow, color: m.color }}>→</div>
          </div>
        ))}
      </div>

      {/* Footer note */}
      <div style={s.footer}>Maruti Trucks · Birgunj · All figures in NPR</div>
    </div>
  );
}

const s = {
  qaRow:      { display: 'flex', gap: 12, marginBottom: 28, flexWrap: 'wrap' },
  qaBtn:      { padding: '10px 22px', border: 'none', borderRadius: 8, color: '#fff', fontSize: 14, fontWeight: 600, cursor: 'pointer', boxShadow: '0 2px 6px rgba(0,0,0,0.15)' },
  grid:       { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: 18 },
  card:       { background: '#fff', borderRadius: 12, boxShadow: '0 1px 6px rgba(0,0,0,0.08)', cursor: 'pointer', overflow: 'hidden', position: 'relative', transition: 'box-shadow 0.2s', paddingBottom: 16 },
  cardAccent: { height: 5 },
  cardBody:   { display: 'flex', alignItems: 'flex-start', gap: 14, padding: '16px 16px 8px' },
  cardIcon:   { fontSize: 30, lineHeight: 1, marginTop: 2 },
  cardTitle:  { fontSize: 15, fontWeight: 700, color: '#1e293b', marginBottom: 4 },
  cardDesc:   { fontSize: 12, color: '#64748b', lineHeight: 1.5 },
  cardStat:   { display: 'flex', alignItems: 'baseline', gap: 4, padding: '0 16px', marginTop: 4 },
  statNum:    { fontSize: 22, fontWeight: 800 },
  statLabel:  { fontSize: 11, opacity: 0.8 },
  cardArrow:  { position: 'absolute', bottom: 14, right: 16, fontSize: 18, fontWeight: 700 },
  footer:     { marginTop: 40, textAlign: 'center', fontSize: 12, color: '#94a3b8' },
};
